import { create } from 'zustand';
import { Cell, generateBoard } from '../utils/gameUtils';
import { supabase } from '../lib/supabase';

export interface LeaderboardEntry {
  id?: number;
  nickname: string;
  score: number; // clicks
  created_at?: string;
}

export interface DanmuRecord {
  id?: number;
  nickname: string;
  content: string;
  created_at?: string;
}

export interface GameMove {
  row: number;
  col: number;
  result: 'empty' | 'body' | 'head';
  time: number;
}

export interface Challenge {
  id: string;
  creator_nickname: string;
  board_config: any[]; // The raw planes array or board state
  total_heads: number;
  best_solver_nickname: string | null;
  best_solver_clicks: number | null;
  created_at: string;
}

export interface GameRecord {
  id: string;
  timestamp: number;
  mode: 'classic' | 'custom' | 'challenge';
  clicks: number;
  isWin: boolean;
  totalHeads: number;
  foundHeads: number;
  moves: GameMove[];
  challengeId?: string; // If playing a challenge
}

interface GameState {
  board: Cell[][];
  totalHeads: number;
  foundHeads: number;
  clicks: number;
  isGameOver: boolean;
  isWin: boolean;
  moves: GameMove[];
  history: GameRecord[];

  nickname: string;
  setNickname: (name: string) => void;
  gameMode: 'classic' | 'custom' | 'challenge';
  setGameMode: (mode: 'classic' | 'custom' | 'challenge') => void;
  
  // Challenge Mode State
  challenges: Challenge[];
  activeChallengeId: string | null;
  fetchChallenges: () => Promise<void>;
  createChallenge: (boardConfig: any[], totalHeads: number) => Promise<boolean>;
  setActiveChallenge: (challengeId: string) => void;
  updateChallengeRecord: (challengeId: string, clicks: number) => Promise<void>;

  leaderboard: LeaderboardEntry[];
  fetchLeaderboard: () => Promise<void>;
  addToLeaderboard: (score: number) => Promise<void>;

  sendDanmuRecord: (content: string) => Promise<void>;
  fetchDanmuRecords: () => Promise<DanmuRecord[]>;

  planeCounts: number[];
  setPlaneCounts: (counts: number[]) => void;

  initGame: () => void;
  revealCell: (row: number, col: number) => void;
  toggleMark: (row: number, col: number) => void;
  
  isMarkMode: boolean;
  toggleMarkMode: () => void;
  
  logout: () => void;
  revealAll: () => void;
  saveGameRecord: () => void;
  loadHistory: () => void;
}

export const useGameStore = create<GameState>((set, get) => ({
  board: [],
  totalHeads: 0,
  foundHeads: 0,
  clicks: 0,
  isGameOver: false,
  isWin: false,
  moves: [],
  history: [],
  isMarkMode: false,
  
  toggleMarkMode: () => set((state) => ({ isMarkMode: !state.isMarkMode })),

  nickname: localStorage.getItem('nickname') || '',
  setNickname: (name) => {
    localStorage.setItem('nickname', name);
    set({ nickname: name });
    get().loadHistory();
  },
  
  loadHistory: async () => {
    const { nickname } = get();
    if (!nickname) {
        set({ history: [] });
        return;
    }
    
    // Load from Supabase instead of LocalStorage
    const { data, error } = await supabase
      .from('game_records')
      .select('*')
      .eq('nickname', nickname)
      .order('created_at', { ascending: false });

    if (error) {
        console.error('Error loading history:', error);
        set({ history: [] });
    } else if (data) {
        // Map database fields to GameRecord interface
        // Database columns are snake_case, but interface is camelCase
        const history: GameRecord[] = data.map(item => ({
            id: item.id,
            nickname: item.nickname,
            mode: item.mode,
            clicks: item.clicks,
            isWin: item.is_win,
            totalHeads: item.total_heads,
            foundHeads: item.found_heads,
            moves: item.moves,
            timestamp: item.timestamp
        }));
        set({ history });
    }
  },
  
  gameMode: 'classic',
  setGameMode: (mode) => {
    if (mode === 'classic') {
      set({ gameMode: mode, planeCounts: [1, 1, 1], activeChallengeId: null });
    } else {
      set({ gameMode: mode, activeChallengeId: null });
    }
    // Restart game when mode changes (unless it's challenge mode, which will wait for a challenge selection)
    if (mode !== 'challenge') {
      setTimeout(() => get().initGame(), 0);
    }
  },

  challenges: [],
  activeChallengeId: null,
  
  fetchChallenges: async () => {
    const { data, error } = await supabase
      .from('challenges')
      .select('*')
      .order('created_at', { ascending: false });
    if (!error && data) {
      set({ challenges: data as Challenge[] });
    }
  },

  createChallenge: async (boardConfig, totalHeads) => {
    const { nickname } = get();
    if (!nickname) return false;
    
    // Check if the user has created a challenge before to avoid spam, but for now we just insert
    try {
        const { error } = await supabase
        .from('challenges')
        .insert([{
            creator_nickname: nickname,
            board_config: boardConfig,
            total_heads: totalHeads
        }]);
        
        if (error) {
            console.error('Error creating challenge:', error.message || error);
            return false;
        }
        get().fetchChallenges();
        return true;
    } catch (e) {
        console.error('Exception creating challenge:', e);
        return false;
    }
  },

  setActiveChallenge: (challengeId) => {
    set({ activeChallengeId: challengeId, gameMode: 'challenge' });
    setTimeout(() => get().initGame(), 0);
  },

  updateChallengeRecord: async (challengeId, clicks) => {
    const { nickname, challenges } = get();
    const challenge = challenges.find(c => c.id === challengeId);
    
    if (challenge && (!challenge.best_solver_clicks || clicks < challenge.best_solver_clicks)) {
      const { error } = await supabase
        .from('challenges')
        .update({
          best_solver_nickname: nickname,
          best_solver_clicks: clicks
        })
        .eq('id', challengeId);
        
      if (!error) {
        get().fetchChallenges();
      }
    }
  },

  leaderboard: [],
  
  fetchLeaderboard: async () => {
    const { data, error } = await supabase
      .from('leaderboard')
      .select('*')
      .order('score', { ascending: true }); // Get all to filter in JS for now, or use complex SQL
      
    if (error) {
      console.error('Error fetching leaderboard:', error);
      return;
    }
    
    if (data) {
      // Group by nickname and take the min score
      const highestScores = data.reduce((acc: any, curr) => {
        if (!acc[curr.nickname] || curr.score < acc[curr.nickname].score) {
          acc[curr.nickname] = curr;
        }
        return acc;
      }, {});

      const uniqueLeaderboard = Object.values(highestScores)
        .sort((a: any, b: any) => a.score - b.score)
        .slice(0, 20);

      set({ leaderboard: uniqueLeaderboard as LeaderboardEntry[] });
    }
  },

  addToLeaderboard: async (score) => {
    const { nickname } = get();
    if (!nickname) return;
    
    // Insert into Supabase
    const { error } = await supabase
      .from('leaderboard')
      .insert([{ nickname, score }]);
      
    if (error) {
      console.error('Error adding to leaderboard:', error);
    } else {
      // Refresh leaderboard after adding
      get().fetchLeaderboard();
    }
  },

  sendDanmuRecord: async (content: string) => {
    const { nickname } = get();
    if (!nickname) return;
    
    const { error } = await supabase
        .from('danmus')
        .insert([{ nickname, content }]);
        
    if (error) {
        console.error('Error saving danmu:', error);
    }
  },

  fetchDanmuRecords: async () => {
    // Fetch latest 50 danmus to use as a pool for random display
    const { data, error } = await supabase
        .from('danmus')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);
        
    if (error) {
        console.error('Error fetching danmus:', error);
        return [];
    }
    return data || [];
  },

  planeCounts: [1, 1, 1],
  setPlaneCounts: (counts) => set({ planeCounts: counts }),

  initGame: () => {
    const { planeCounts, gameMode, activeChallengeId, challenges } = get();
    
    let board: Cell[][];
    let totalHeads: number;
    let actualPlaneCounts = [...planeCounts]; // Local copy to update for challenge mode

    if (gameMode === 'challenge' && activeChallengeId) {
      const challenge = challenges.find(c => c.id === activeChallengeId);
      if (challenge) {
        // Reset local plane counts
        actualPlaneCounts = [0, 0, 0];
        
        // Reconstruct board from challenge config
        board = Array.from({ length: 16 }, (_, r) =>
          Array.from({ length: 16 }, (_, c) => ({
            row: r,
            col: c,
            type: 'empty',
            revealed: false,
            marked: false,
          }))
        );
        
        challenge.board_config.forEach((plane: any) => {
            // Count the shape type
            if (plane.shapeIdx !== undefined && plane.shapeIdx >= 0 && plane.shapeIdx < 3) {
                actualPlaneCounts[plane.shapeIdx]++;
            }

            for (let i = 0; i < 5; i++) {
                for (let j = 0; j < 5; j++) {
                    if (plane.shape[i][j] !== 0) {
                        const r = plane.r + i;
                        const c = plane.c + j;
                        if (r >= 0 && r < 16 && c >= 0 && c < 16) {
                            board[r][c].type = plane.shape[i][j] === 2 ? 'head' : 'body';
                        }
                    }
                }
            }
        });
        totalHeads = challenge.total_heads;
      } else {
        const generated = generateBoard(actualPlaneCounts);
        board = generated.board;
        totalHeads = generated.totalHeads;
      }
    } else {
      const generated = generateBoard(actualPlaneCounts);
      board = generated.board;
      totalHeads = generated.totalHeads;
    }

    set({
      board,
      totalHeads,
      foundHeads: 0,
      clicks: 0,
      isGameOver: false,
      isWin: false,
      moves: [],
      isMarkMode: false,
      planeCounts: actualPlaneCounts, // Update the store with the actual counts for UI rendering
    });
  },

  logout: () => {
    localStorage.removeItem('nickname');
    set({
      nickname: '',
      board: [],
      totalHeads: 0,
      foundHeads: 0,
      clicks: 0,
      isGameOver: false,
      isWin: false,
      moves: [],
      history: [],
      leaderboard: [],
    });
  },

  revealAll: () => {
    const { board } = get();
    const newBoard = board.map(row => row.map(cell => ({ ...cell, revealed: true })));
    set({ board: newBoard });
  },

  saveGameRecord: async () => {
    const { nickname, gameMode, clicks, isWin, moves, totalHeads, foundHeads, activeChallengeId } = get();
    const record: GameRecord = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      mode: gameMode,
      clicks,
      isWin,
      totalHeads,
      foundHeads,
      moves,
      challengeId: activeChallengeId || undefined
    };

    // Save to Supabase
    // Note: We might need to add challenge_id to game_records if we want to query by it later,
    // but for now we just store it in moves/jsonb or as part of the app state.
    // Let's assume the DB table doesn't have challenge_id yet, so we won't insert it as a column unless we update the DB.
    // Actually, I didn't add challenge_id to game_records. So I'll just save it as is.
    const { error } = await supabase
      .from('game_records')
      .insert([{
        id: record.id,
        nickname,
        mode: record.mode,
        clicks: record.clicks,
        is_win: record.isWin,
        total_heads: record.totalHeads,
        found_heads: record.foundHeads,
        moves: record.moves,
        timestamp: record.timestamp
      }]);

    if (error) {
        console.error('Error saving game record:', error);
    } else {
        // Refresh history
        get().loadHistory();
    }
  },

  revealCell: (row: number, col: number) => {
    const { board, isGameOver, foundHeads, totalHeads, clicks, gameMode, activeChallengeId, addToLeaderboard, updateChallengeRecord, moves, isMarkMode, toggleMark } = get();

    if (isGameOver) return;
    if (board[row][col].revealed) return;

    if (isMarkMode) {
      toggleMark(row, col);
      return;
    }

    if (board[row][col].marked) return; // Don't reveal marked cells unless unmarking them first

    // Create a new board copy to maintain immutability
    const newBoard = board.map((r) => r.map((c) => ({ ...c })));
    const cell = newBoard[row][col];
    cell.revealed = true;

    let newFoundHeads = foundHeads;
    let newIsGameOver = isGameOver;
    let newIsWin = false;

    if (cell.type === 'head') {
      newFoundHeads++;
      if (newFoundHeads === totalHeads) {
        newIsGameOver = true;
        newIsWin = true;
      }
    }

    const newClicks = clicks + 1;
    const newMoves = [...moves, { row, col, result: cell.type, time: Date.now() }];

    set({
      board: newBoard,
      clicks: newClicks,
      foundHeads: newFoundHeads,
      isGameOver: newIsGameOver,
      isWin: newIsWin,
      moves: newMoves,
    });

    if (newIsGameOver) {
      get().saveGameRecord();
      // Delay reveal all for effect
      setTimeout(() => {
          get().revealAll();
      }, 500);
      
      // If game won and classic mode, add to leaderboard
      if (newIsWin && gameMode === 'classic') {
        addToLeaderboard(newClicks);
      }
      // If game won and challenge mode, update challenge record
      if (newIsWin && gameMode === 'challenge' && activeChallengeId) {
        updateChallengeRecord(activeChallengeId, newClicks);
      }
    }
  },

  toggleMark: (row: number, col: number) => {
    const { board, isGameOver } = get();

    if (isGameOver) return;
    if (board[row][col].revealed) return;

    const newBoard = board.map((r) => r.map((c) => ({ ...c })));
    newBoard[row][col].marked = !newBoard[row][col].marked;

    set({ board: newBoard });
  },
}));