import React, { useRef } from 'react';
import { Cell as CellType } from '../utils/gameUtils';

interface CellProps {
  cell: CellType;
  onClick: () => void;
  onContextMenu: (e: React.MouseEvent) => void;
}

const Cell: React.FC<CellProps> = ({ cell, onClick, onContextMenu }) => {
  const { revealed, type, marked } = cell;
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);

  const handleTouchStart = () => {
    if (revealed) return;
    longPressTimer.current = setTimeout(() => {
      // Long press detected, trigger mark
      onContextMenu({ preventDefault: () => {} } as React.MouseEvent);
      // Vibrate if supported
      if (navigator.vibrate) navigator.vibrate(50);
    }, 400); // 400ms feels better
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  const handleTouchMove = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  let content = '';
  let bgColor = 'bg-white';
  let cursor = 'cursor-pointer';

  if (revealed) {
    cursor = 'cursor-default';
    if (type === 'head') {
      bgColor = 'bg-red-500';
    } else if (type === 'body') {
      bgColor = 'bg-blue-500';
    } else {
      bgColor = 'bg-gray-200';
    }
  } else if (marked) {
    bgColor = 'bg-yellow-200';
    content = '🚩';
  }

  return (
    <div className="relative w-full pt-[100%]">
      <div
        onClick={onClick}
        onContextMenu={onContextMenu}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
        onTouchMove={handleTouchMove}
        onTouchCancel={handleTouchEnd}
        style={{ touchAction: 'none' }} // Prevent scrolling/zooming on the grid itself for better game feel
        className={`
          absolute inset-0
          border border-gray-400
          flex items-center justify-center
          text-sm font-bold select-none
          transition-colors duration-200
          ${bgColor} ${cursor}
          hover:opacity-80
        `}
      >
        {content}
      </div>
    </div>
  );
};

export default Cell;
