import { GRID_SIZE, PLANE_SHAPES, PlaneShape } from './constants';

export type CellType = 'empty' | 'body' | 'head';

export interface Cell {
  row: number;
  col: number;
  type: CellType;
  revealed: boolean;
  marked: boolean;
}

// Rotate a 5x5 matrix 90 degrees clockwise
export const rotateMatrix = (matrix: number[][]): number[][] => {
  const N = matrix.length;
  const rotated = Array.from({ length: N }, () => Array(N).fill(0));
  for (let i = 0; i < N; i++) {
    for (let j = 0; j < N; j++) {
      rotated[j][N - 1 - i] = matrix[i][j];
    }
  }
  return rotated;
};

// Generate a new board with random planes
export const generateBoard = (planeCounts: number[] = [1, 1, 1]): { board: Cell[][]; totalHeads: number } => {
  // Initialize empty board
  const board: Cell[][] = Array.from({ length: GRID_SIZE }, (_, r) =>
    Array.from({ length: GRID_SIZE }, (_, c) => ({
      row: r,
      col: c,
      type: 'empty',
      revealed: false,
      marked: false,
    }))
  );

  let totalHeads = 0;
  const planesToPlace: PlaneShape[] = [];

  // Add planes based on counts
  planeCounts.forEach((count, index) => {
    if (index < PLANE_SHAPES.length) {
      for (let i = 0; i < count; i++) {
        planesToPlace.push(PLANE_SHAPES[index]);
      }
    }
  });

  for (const shape of planesToPlace) {
    let placed = false;
    let attempts = 0;
    while (!placed && attempts < 1000) {
      // Random rotation (0, 1, 2, 3 times 90 deg)
      const rotations = Math.floor(Math.random() * 4);
      let currentShape = shape;
      for (let i = 0; i < rotations; i++) {
        currentShape = rotateMatrix(currentShape);
      }

      // Random position (top-left corner of 5x5 grid)
      // Grid is 16x16, shape is 5x5. Valid row/col indices: 0 to 11.
      const row = Math.floor(Math.random() * (GRID_SIZE - 5 + 1));
      const col = Math.floor(Math.random() * (GRID_SIZE - 5 + 1));

      if (canPlace(board, currentShape, row, col)) {
        place(board, currentShape, row, col);
        totalHeads++;
        placed = true;
      }
      attempts++;
    }
  }

  return { board, totalHeads };
};

// Check if a plane can be placed without overwriting an existing head
const canPlace = (board: Cell[][], shape: number[][], startRow: number, startCol: number): boolean => {
  for (let i = 0; i < 5; i++) {
    for (let j = 0; j < 5; j++) {
      if (shape[i][j] !== 0) {
        const r = startRow + i;
        const c = startCol + j;
        
        // Check bounds (though startRow/startCol limit should handle this)
        if (r >= GRID_SIZE || c >= GRID_SIZE) return false;

        // STRICT NO OVERLAP RULE:
        // A plane cannot overlap with ANY existing non-empty cell (head or body).
        if (board[r][c].type !== 'empty') return false;
      }
    }
  }
  return true;
};

const place = (board: Cell[][], shape: number[][], startRow: number, startCol: number) => {
  for (let i = 0; i < 5; i++) {
    for (let j = 0; j < 5; j++) {
      const val = shape[i][j];
      if (val !== 0) {
        const r = startRow + i;
        const c = startCol + j;
        
        if (val === 2) {
          board[r][c].type = 'head';
        } else if (val === 1) {
          // Only set to body if it's currently empty.
          // If it's already body, stays body.
          // If it's head, we shouldn't be here because canPlace checked it.
          if (board[r][c].type === 'empty') {
            board[r][c].type = 'body';
          }
        }
      }
    }
  }
};
