import React, { useState } from 'react';
import { useGameStore } from '../store/useGameStore';
import { RefreshCw, HelpCircle, Settings, Trophy, Flag, MousePointerClick } from 'lucide-react';
import { PLANE_SHAPES } from '../utils/constants';

interface ControlsProps {
  onOpenRules: () => void;
  onOpenLeaderboard: () => void;
}

const Controls: React.FC<ControlsProps> = ({ onOpenRules, onOpenLeaderboard }) => {
  const { 
    clicks, foundHeads, totalHeads, initGame, isGameOver, isWin, 
    planeCounts, setPlaneCounts, gameMode, setGameMode,
    isMarkMode, toggleMarkMode, activeChallengeId, challenges
  } = useGameStore();
  
  const [showSettings, setShowSettings] = useState(false);
  const [tempCounts, setTempCounts] = useState(planeCounts);

  const activeChallenge = gameMode === 'challenge' ? challenges.find(c => c.id === activeChallengeId) : null;

  React.useEffect(() => {
    setTempCounts(planeCounts);
  }, [planeCounts]);

  const handleCountChange = (index: number, value: string) => {
    const val = parseInt(value) || 0;
    const clamped = Math.max(0, Math.min(5, val));
    const newCounts = [...tempCounts];
    newCounts[index] = clamped;
    setTempCounts(newCounts);
  };

  const applySettings = () => {
    const expectedHeads = tempCounts.reduce((a, b) => a + b, 0);
    setPlaneCounts(tempCounts);
    setShowSettings(false);
    setTimeout(() => {
        initGame();
        const state = useGameStore.getState();
        if (state.totalHeads < expectedHeads) {
            alert(`无法完全放置所有飞机！\n请求: ${expectedHeads} 架\n实际放置: ${state.totalHeads} 架\n请尝试减少飞机数量或重试。`);
        }
    }, 0);
  };

  return (
    <div className="w-full max-w-md bg-white p-4 rounded-xl shadow-md border border-gray-100">
      
      {/* Mode Switcher */}
      <div className="flex bg-gray-100 p-1 rounded-lg mb-4">
        <button
          onClick={() => setGameMode('classic')}
          className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${
            gameMode === 'classic' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          经典模式
        </button>
        <button
          onClick={() => setGameMode('custom')}
          className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${
            gameMode === 'custom' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          自定义模式
        </button>
        <button
          onClick={() => setGameMode('challenge')}
          className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${
            gameMode === 'challenge' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          挑战模式
        </button>
      </div>

      <div className="flex justify-between items-center mb-4">
        <div>
          <div className="text-lg font-bold text-gray-800">
            点击次数: <span className="text-blue-600">{clicks}</span>
          </div>
          <div className="text-lg font-bold text-gray-800">找到机头: <span className="text-green-600">{foundHeads} / {totalHeads}</span></div>
          {activeChallenge && (
            <div className="text-xs text-gray-500 mt-1">
              🏆 最佳: {activeChallenge.best_solver_nickname ? `${activeChallenge.best_solver_nickname} (${activeChallenge.best_solver_clicks}步)` : '暂无人破解'}
            </div>
          )}
        </div>
        
        <div className="flex gap-2">
          {gameMode === 'classic' && (
            <button 
              onClick={onOpenLeaderboard}
              className="p-2 bg-yellow-100 hover:bg-yellow-200 rounded-lg border border-yellow-300 transition-colors"
              title="排行榜"
            >
              <Trophy size={20} className="text-yellow-600" />
            </button>
          )}

          {gameMode === 'custom' && (
            <button 
              onClick={() => {
                setShowSettings(!showSettings);
                setTempCounts(planeCounts);
              }}
              className={`flex items-center gap-1.5 px-3 py-2 rounded-lg border transition-colors font-medium text-sm shadow-sm ${
                showSettings 
                  ? 'bg-purple-100 border-purple-300 text-purple-700' 
                  : 'bg-purple-50 hover:bg-purple-100 border-purple-200 text-purple-600'
              }`}
              title="自定义飞机数量"
            >
              <Settings size={16} />
              设置
            </button>
          )}

          <button 
            onClick={initGame}
            className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors font-medium shadow-sm active:transform active:scale-95"
          >
            <RefreshCw size={18} />
            新游戏
          </button>
          
          <button 
            onClick={onOpenRules}
            className="p-2 bg-gray-100 hover:bg-gray-200 rounded-lg border border-gray-300 transition-colors"
            title="规则"
          >
            <HelpCircle size={20} className="text-gray-700" />
          </button>
        </div>
      </div>

      {/* Settings Panel (Custom Mode Only) */}
      {showSettings && gameMode === 'custom' && (
        <div className="mb-4 p-4 bg-gray-50 rounded-lg border border-gray-200 animate-in slide-in-from-top-2">
          <h3 className="font-bold mb-3 text-gray-700">设置飞机数量</h3>
          <div className="flex gap-4 justify-center mb-4">
            {tempCounts.map((count, idx) => (
              <div key={idx} className="flex flex-col items-center">
                <span className="text-xs text-gray-500 mb-1">类型 {idx + 1}</span>
                <input
                  type="number"
                  min="0"
                  max="5"
                  value={count}
                  onChange={(e) => handleCountChange(idx, e.target.value)}
                  className="w-12 p-1 text-center border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            ))}
          </div>
          <button 
            onClick={applySettings}
            className="w-full py-2 bg-gray-800 hover:bg-gray-900 text-white rounded transition-colors text-sm font-medium"
          >
            应用并开始新游戏
          </button>
        </div>
      )}

      {isGameOver && (
        <div className={`p-3 rounded-lg text-center font-bold text-white mb-4 shadow-sm animate-in zoom-in-95 ${isWin ? 'bg-green-500' : 'bg-red-500'}`}>
          {isWin ? '🎉 恭喜你找到了所有机头！' : '游戏结束'}
          {isWin && gameMode === 'classic' && (
             <div className="text-xs font-normal mt-1 opacity-90">成绩已记录到排行榜</div>
          )}
          {isWin && gameMode === 'challenge' && (
             <div className="text-xs font-normal mt-1 opacity-90">你的挑战成绩已更新！</div>
          )}
        </div>
      )}

      {/* Plane Shapes Display & Mode Toggle */}
      <div className="mt-2 pt-4 border-t border-gray-100">
        <h3 className="font-bold mb-3 text-xs text-gray-500 text-center uppercase tracking-wider">当前飞机形态</h3>
        <div className="flex gap-4 justify-center flex-wrap items-center">
          {/* Move Toggle Button Here */}
          <button 
            onClick={toggleMarkMode}
            className={`flex flex-col items-center justify-center w-12 h-12 rounded-xl transition-colors font-medium shadow-sm active:transform active:scale-95 border-2 ${
              isMarkMode 
                ? 'bg-red-50 text-red-600 border-red-200' 
                : 'bg-blue-50 text-blue-600 border-blue-200 hover:bg-blue-100'
            }`}
            title={isMarkMode ? "切换为点击模式" : "切换为标记模式"}
          >
            {isMarkMode ? <Flag size={20} /> : <MousePointerClick size={20} />}
            <span className="text-[10px] mt-0.5">{isMarkMode ? '标记' : '点击'}</span>
          </button>
          
          <div className="w-px h-10 bg-gray-200 mx-1"></div> {/* Divider */}

          {PLANE_SHAPES.map((shape, idx) => {
            if (planeCounts[idx] === 0) return null;
            return (
              <div key={idx} className="flex flex-col items-center group">
                <div className="grid grid-cols-5 gap-px border border-gray-200 bg-white p-1 shadow-sm group-hover:shadow-md transition-shadow">
                  {shape.flat().map((cell, cIdx) => (
                    <div 
                      key={cIdx} 
                      className={`w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-[1px] ${cell === 2 ? 'bg-red-500' : cell === 1 ? 'bg-blue-500' : 'invisible'}`}
                    />
                  ))}
                </div>
                <span className="text-xs text-gray-400 mt-1 font-mono">x{planeCounts[idx]}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default Controls;