import React, { useState, useEffect, useRef } from 'react';
import { useGameStore } from '../store/useGameStore';
import { Send } from 'lucide-react';

interface Danmu {
  id: string;
  text: string;
  top: number; // percentage
  speed: number;
  color: string;
}

const DanmuOverlay: React.FC = () => {
  const [danmus, setDanmus] = useState<Danmu[]>([]);
  const [inputText, setInputText] = useState('');
  const [historyDanmus, setHistoryDanmus] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const { nickname, clicks, foundHeads, totalHeads, isGameOver, isWin, sendDanmuRecord, fetchDanmuRecords } = useGameStore();
  const prevClicks = useRef(clicks);
  const prevFoundHeads = useRef(foundHeads);
  const prevIsGameOver = useRef(isGameOver);

  // Fetch real danmu history on mount
  useEffect(() => {
    fetchDanmuRecords().then(records => {
        if (records.length > 0) {
            setHistoryDanmus(records.map(r => `${r.nickname}: ${r.content}`));
        }
    });
  }, [fetchDanmuRecords]);

  const addDanmu = (text: string, isSystem = false) => {
    const id = Math.random().toString(36).substring(2, 11);
    // Limit to top 30% of screen to avoid blocking game board
    const top = Math.random() * 30 + 5; 
    // Slower speed: 10s to 20s
    const speed = Math.random() * 10 + 10; 
    const color = isSystem ? '#ffeb3b' : '#ffffff';
    
    setDanmus(prev => [...prev, { id, text, top, speed, color }]);

    // Remove after animation
    setTimeout(() => {
      setDanmus(prev => prev.filter(d => d.id !== id));
    }, speed * 1000);
  };

  const handleSend = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputText.trim()) return;
    
    // Show locally immediately
    addDanmu(`${nickname}: ${inputText}`);
    
    // Save to database
    sendDanmuRecord(inputText);
    
    setInputText('');
  };

  // Continuous random danmu loop mixing real history and fake defaults
  useEffect(() => {
      const interval = setInterval(() => {
          if (Math.random() > 0.6) { // 40% chance to spawn per interval
              const defaultMessages = [
                  "加油！", "小心炸弹！", "机头在哪里？", "这也太难了吧", 
                  "有人通关了吗？", "我猜在左上角", "运气真好", "再来一局",
                  "这个游戏好玩", "注意观察", "别乱点", "稳住我们能赢",
                  "666", "厉害了", "前排围观", "打卡", "求攻略"
              ];
              
              let finalMessage = '';
              
              // 30% chance to pick from real database history if available
              if (historyDanmus.length > 0 && Math.random() > 0.7) {
                  finalMessage = historyDanmus[Math.floor(Math.random() * historyDanmus.length)];
              } else {
                  // Fallback to fake users
                  const text = defaultMessages[Math.floor(Math.random() * defaultMessages.length)];
                  const randomUser = Math.random().toString(36).substring(7); 
                  finalMessage = `玩家${randomUser}: ${text}`;
              }
              
              const id = Math.random().toString(36).substring(2, 9);
              // Limit to top 30% of screen to avoid blocking game board
              const top = Math.random() * 30 + 5; 
              // Slower speed: 10s to 20s
              const speed = Math.random() * 10 + 10; 
              const color = '#ffffff'; // User color
              
              setDanmus(prev => [...prev, { id, text: finalMessage, top, speed, color }]);
              
              setTimeout(() => {
                setDanmus(prev => prev.filter(d => d.id !== id));
              }, speed * 1000);
          }
      }, 2000); // Check every 2 seconds

      return () => clearInterval(interval);
  }, []);

  // System Events
  useEffect(() => {
    if (clicks > prevClicks.current) {
        // Maybe random encouragement?
        if (clicks % 10 === 0) {
            addDanmu(`加油！坚持就是胜利！`, true);
        }
    }
    prevClicks.current = clicks;
  }, [clicks]);

  useEffect(() => {
    if (foundHeads > prevFoundHeads.current) {
        addDanmu(`太棒了！找到了一个机头！`, true);
    }
    prevFoundHeads.current = foundHeads;
  }, [foundHeads]);

  useEffect(() => {
    if (isGameOver && !prevIsGameOver.current) {
        if (isWin) {
            addDanmu(`恭喜通关！大神受我一拜！`, true);
        } else {
            addDanmu(`遗憾惜败，再接再厉！`, true);
        }
    }
    prevIsGameOver.current = isGameOver;
  }, [isGameOver, isWin]);

  // Initial greeting
  useEffect(() => {
      addDanmu(`欢迎来到寻机头小游戏 v3.0`, true);
  }, []);

  return (
    <div className="absolute inset-0 pointer-events-none overflow-hidden z-10 rounded-lg">
      {/* Danmu Track */}
      <div ref={containerRef} className="relative w-full h-full">
        {danmus.map(danmu => (
          <div
            key={danmu.id}
            className="absolute whitespace-nowrap font-bold tracking-wide animate-danmu pointer-events-none"
            style={{
              top: `${danmu.top}%`,
              color: danmu.color,
              // Add strong text-shadow (stroke effect) for better visibility on grids
              textShadow: '1px 1px 0 #000, -1px -1px 0 #000, 1px -1px 0 #000, -1px 1px 0 #000, 2px 2px 4px rgba(0,0,0,0.6)',
              animationDuration: `${danmu.speed}s`,
              right: '-100%', // Start off-screen
              // Responsive font size
              fontSize: 'clamp(1rem, 4vw, 1.25rem)',
              // Add slight padding to avoid clipping the shadow
              padding: '0.2em 0'
            }}
          >
            {danmu.text}
          </div>
        ))}
      </div>

      {/* Input Area (Fixed to bottom of screen across all devices) */}
      <div 
        className="fixed bottom-0 left-0 right-0 p-4 pb-safe flex justify-center z-[100] pointer-events-none"
        style={{ 
            // iOS safe area support for devices with home indicator
            paddingBottom: 'max(1rem, env(safe-area-inset-bottom))',
            // Ensure it sits above everything but allows clicks to pass through except on the form
            background: 'linear-gradient(to top, rgba(249, 250, 251, 0.9), transparent)' 
        }}
      >
        <form 
            onSubmit={handleSend} 
            className="flex items-center gap-2 w-full max-w-md bg-gray-800 p-1.5 pl-4 rounded-full shadow-2xl pointer-events-auto transition-transform active:scale-[0.98]"
        >
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="发条弹幕参与讨论..."
            className="flex-1 bg-transparent text-white placeholder-gray-400 outline-none text-[16px] h-10"
            style={{ 
                // Prevent iOS zooming on focus by ensuring font-size is at least 16px
                fontSize: '16px' 
            }}
          />
          <button 
            type="submit"
            disabled={!inputText.trim()}
            className="p-2.5 bg-blue-600 rounded-full text-white hover:bg-blue-500 disabled:bg-gray-600 disabled:text-gray-400 transition-colors shadow-sm flex-shrink-0"
          >
            <Send size={18} />
          </button>
        </form>
      </div>
      
      <style>{`
        @keyframes danmu {
          from { left: 100%; transform: translateX(0); }
          to { left: 0%; transform: translateX(-100%); }
        }
        .animate-danmu {
          animation-name: danmu;
          animation-timing-function: linear;
          animation-fill-mode: forwards;
        }
      `}</style>
    </div>
  );
};

export default DanmuOverlay;