import React, { useState, useEffect } from 'react';
import { X, Play, User, Trophy, Plus } from 'lucide-react';
import { useGameStore, Challenge } from '../store/useGameStore';

interface ChallengeListProps {
  onClose: () => void;
  onCreateNew: () => void;
}

const ChallengeList: React.FC<ChallengeListProps> = ({ onClose, onCreateNew }) => {
  const { challenges, fetchChallenges, setActiveChallenge } = useGameStore();

  useEffect(() => {
    fetchChallenges();
  }, [fetchChallenges]);

  const handlePlay = (challengeId: string) => {
    setActiveChallenge(challengeId);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl w-full max-w-2xl max-h-[90vh] shadow-2xl flex flex-col relative" onClick={e => e.stopPropagation()}>
        
        {/* Header */}
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-gray-50 rounded-t-2xl">
          <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            ⚔️ 挑战模式
          </h2>
          <button onClick={onClose} className="p-2 bg-gray-200 hover:bg-gray-300 rounded-full transition-colors">
            <X size={20} className="text-gray-600" />
          </button>
        </div>

        {/* Action Bar */}
        <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white">
            <p className="text-sm text-gray-500">游玩其他玩家创建的自定义地图，或者...</p>
            <button 
                onClick={() => {
                    onClose();
                    onCreateNew();
                }}
                className="flex items-center gap-1 px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg text-sm font-bold shadow-sm transition-colors"
            >
                <Plus size={16} /> 创建我的挑战图
            </button>
        </div>

        {/* List */}
        <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
          {challenges.length === 0 ? (
            <div className="text-center py-10 text-gray-400">
              <p>暂无挑战图，快来创建第一个吧！</p>
            </div>
          ) : (
            challenges.map((challenge) => (
              <div 
                key={challenge.id}
                className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 hover:border-blue-300 transition-colors"
              >
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-bold text-gray-800">{challenge.creator_nickname} 的挑战</span>
                    <span className="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">
                      {challenge.total_heads} 架飞机
                    </span>
                  </div>
                  <div className="text-sm text-gray-500 flex items-center gap-4 mt-2">
                    <span className="flex items-center gap-1">
                        <User size={14} /> 创建者: {challenge.creator_nickname}
                    </span>
                    <span className="flex items-center gap-1">
                        <Trophy size={14} className={challenge.best_solver_nickname ? 'text-yellow-500' : 'text-gray-400'} /> 
                        最佳: {challenge.best_solver_nickname ? `${challenge.best_solver_nickname} (${challenge.best_solver_clicks}步)` : '暂无'}
                    </span>
                  </div>
                </div>
                <button 
                  onClick={() => handlePlay(challenge.id)}
                  className="w-full sm:w-auto flex items-center justify-center gap-1 px-5 py-2 bg-blue-100 hover:bg-blue-200 text-blue-700 rounded-lg font-bold transition-colors"
                >
                  <Play size={16} /> 挑战
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default ChallengeList;