import React, { useState } from 'react';
import { X, RotateCw, Save, Trash2 } from 'lucide-react';
import { useGameStore } from '../store/useGameStore';
import { PLANE_SHAPES, GRID_SIZE } from '../utils/constants';
import { rotateMatrix } from '../utils/gameUtils';

interface ChallengeCreatorProps {
  onClose: () => void;
}

interface PlacedPlane {
  id: string;
  shapeIdx: number;
  shape: number[][]; // The actual matrix after rotations
  r: number;
  c: number;
}

const ChallengeCreator: React.FC<ChallengeCreatorProps> = ({ onClose }) => {
  const { createChallenge } = useGameStore();
  const [placedPlanes, setPlacedPlanes] = useState<PlacedPlane[]>([]);
  const [selectedShapeIdx, setSelectedShapeIdx] = useState<number>(0);
  const [currentRotation, setCurrentRotation] = useState<number>(0); // 0, 1, 2, 3
  const [hoverPos, setHoverPos] = useState<{ r: number; c: number } | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Get the currently selected and rotated shape
  const getCurrentShape = () => {
    let shape = PLANE_SHAPES[selectedShapeIdx];
    for (let i = 0; i < currentRotation; i++) {
      shape = rotateMatrix(shape);
    }
    return shape;
  };

  const currentShape = getCurrentShape();

  // Check if current shape can be placed at (r, c)
  const canPlace = (r: number, c: number) => {
    for (let i = 0; i < 5; i++) {
      for (let j = 0; j < 5; j++) {
        if (currentShape[i][j] !== 0) {
          const nr = r + i;
          const nc = c + j;
          // Bounds check
          if (nr < 0 || nr >= GRID_SIZE || nc < 0 || nc >= GRID_SIZE) return false;
          
          // Overlap check
          for (const plane of placedPlanes) {
            for (let pi = 0; pi < 5; pi++) {
              for (let pj = 0; pj < 5; pj++) {
                if (plane.shape[pi][pj] !== 0) {
                  if (plane.r + pi === nr && plane.c + pj === nc) return false;
                }
              }
            }
          }
        }
      }
    }
    return true;
  };

  const handleCellClick = (r: number, c: number) => {
    if (canPlace(r, c)) {
      setPlacedPlanes([
        ...placedPlanes, 
        {
          id: Math.random().toString(),
          shapeIdx: selectedShapeIdx,
          shape: currentShape,
          r,
          c
        }
      ]);
    }
  };

  const handleSave = async () => {
    if (placedPlanes.length === 0) {
        alert("请至少放置一架飞机！");
        return;
    }
    setIsSaving(true);
    try {
        const success = await createChallenge(placedPlanes, placedPlanes.length);
        if (success) {
            alert("挑战图创建成功！");
            onClose();
        } else {
            alert("创建失败，请确保数据库表 'challenges' 已正确创建并开启了 RLS 权限。");
        }
    } catch (error) {
        console.error("Save error:", error);
        alert("创建时发生异常错误。");
    } finally {
        setIsSaving(false);
    }
  };

  // Build a preview grid
  const grid = Array.from({ length: GRID_SIZE }, () => Array(GRID_SIZE).fill(0));
  
  // Fill placed planes
  placedPlanes.forEach(plane => {
    for (let i = 0; i < 5; i++) {
      for (let j = 0; j < 5; j++) {
        if (plane.shape[i][j] !== 0) {
          grid[plane.r + i][plane.c + j] = plane.shape[i][j] === 2 ? 2 : 1; // 2=head, 1=body
        }
      }
    }
  });

  // Fill hover preview
  let canHoverPlace = false;
  if (hoverPos) {
    canHoverPlace = canPlace(hoverPos.r, hoverPos.c);
    for (let i = 0; i < 5; i++) {
      for (let j = 0; j < 5; j++) {
        if (currentShape[i][j] !== 0) {
          const nr = hoverPos.r + i;
          const nc = hoverPos.c + j;
          if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE) {
              if (grid[nr][nc] === 0) { // Only draw if not overlapping (though canHoverPlace handles logic)
                  grid[nr][nc] = currentShape[i][j] === 2 ? (canHoverPlace ? 4 : 6) : (canHoverPlace ? 3 : 5); 
                  // 3=preview body, 4=preview head, 5=error body, 6=error head
              }
          }
        }
      }
    }
  }

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[95vh] shadow-2xl flex flex-col relative overflow-hidden" onClick={e => e.stopPropagation()}>
        
        {/* Header */}
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-gray-50">
          <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            🛠️ 创建挑战图
          </h2>
          <button onClick={onClose} className="p-2 bg-gray-200 hover:bg-gray-300 rounded-full transition-colors">
            <X size={20} className="text-gray-600" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 flex flex-col lg:flex-row gap-6">
            
            {/* Left: Controls */}
            <div className="w-full lg:w-1/3 flex flex-col gap-4">
                <div className="bg-gray-50 p-4 rounded-xl border border-gray-200">
                    <h3 className="font-bold text-gray-700 mb-2">1. 选择飞机并旋转</h3>
                    <div className="flex gap-2 justify-center mb-4">
                        {PLANE_SHAPES.map((shape, idx) => (
                            <div 
                                key={idx} 
                                onClick={() => setSelectedShapeIdx(idx)}
                                className={`p-2 border-2 rounded-lg cursor-pointer transition-all ${selectedShapeIdx === idx ? 'border-blue-500 bg-blue-50' : 'border-gray-200 bg-white hover:border-blue-300'}`}
                            >
                                <div className="grid grid-cols-5 gap-px">
                                {shape.flat().map((cell, cIdx) => (
                                    <div key={cIdx} className={`w-2 h-2 rounded-[1px] ${cell === 2 ? 'bg-red-500' : cell === 1 ? 'bg-blue-500' : 'invisible'}`} />
                                ))}
                                </div>
                            </div>
                        ))}
                    </div>
                    <button 
                        onClick={() => setCurrentRotation(r => (r + 1) % 4)}
                        className="w-full flex items-center justify-center gap-2 py-2 bg-gray-200 hover:bg-gray-300 text-gray-800 rounded-lg transition-colors font-medium"
                    >
                        <RotateCw size={18} /> 旋转飞机
                    </button>
                </div>

                <div className="bg-gray-50 p-4 rounded-xl border border-gray-200 flex-1">
                    <h3 className="font-bold text-gray-700 mb-2 flex justify-between">
                        <span>已放置: {placedPlanes.length}架</span>
                        {placedPlanes.length > 0 && (
                            <button 
                                onClick={() => setPlacedPlanes([])}
                                className="text-red-500 hover:text-red-700 text-sm flex items-center gap-1"
                            >
                                <Trash2 size={14} /> 清空
                            </button>
                        )}
                    </h3>
                    <p className="text-sm text-gray-500 mb-4">在右侧网格中点击以放置选中的飞机。</p>
                    
                    <button 
                        onClick={handleSave}
                        disabled={placedPlanes.length === 0 || isSaving}
                        className="w-full flex items-center justify-center gap-2 py-3 bg-green-600 hover:bg-green-700 disabled:bg-gray-300 text-white rounded-lg transition-colors font-bold text-lg mt-auto shadow-md"
                    >
                        <Save size={20} /> {isSaving ? '保存中...' : '保存并发布'}
                    </button>
                </div>
            </div>

            {/* Right: Grid */}
            <div className="w-full lg:w-2/3 flex items-center justify-center bg-gray-100 p-4 rounded-xl border border-gray-200">
                <div 
                    className="grid gap-0 border-2 border-gray-800 bg-white w-full max-w-[500px] aspect-square"
                    style={{ gridTemplateColumns: `repeat(${GRID_SIZE}, minmax(0, 1fr))` }}
                    onMouseLeave={() => setHoverPos(null)}
                >
                    {grid.map((row, r) =>
                        row.map((cellType, c) => {
                            let bgColor = 'bg-white';
                            if (cellType === 1) bgColor = 'bg-blue-500'; // placed body
                            if (cellType === 2) bgColor = 'bg-red-500';  // placed head
                            if (cellType === 3) bgColor = 'bg-blue-300 opacity-70'; // preview body
                            if (cellType === 4) bgColor = 'bg-red-300 opacity-70';  // preview head
                            if (cellType === 5) bgColor = 'bg-gray-400 opacity-50'; // error body
                            if (cellType === 6) bgColor = 'bg-gray-600 opacity-50'; // error head

                            return (
                                <div
                                    key={`${r}-${c}`}
                                    className={`relative w-full pt-[100%] border border-gray-300 ${bgColor} cursor-crosshair`}
                                    onMouseEnter={() => setHoverPos({ r, c })}
                                    onClick={() => handleCellClick(r, c)}
                                />
                            );
                        })
                    )}
                </div>
            </div>

        </div>
      </div>
    </div>
  );
};

export default ChallengeCreator;