import React, { useEffect, useState } from 'react';
import { useGameStore } from '../store/useGameStore';

interface LeaderboardProps {
  onClose: () => void;
}

const Leaderboard: React.FC<LeaderboardProps> = ({ onClose }) => {
  const { leaderboard, fetchLeaderboard } = useGameStore();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchLeaderboard().finally(() => setLoading(false));
  }, [fetchLeaderboard]);

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-md max-h-[80vh] flex flex-col transform transition-all scale-100">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
            🏆 排行榜
          </h2>
          <button 
            onClick={onClose} 
            className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 text-gray-500 hover:text-gray-700 text-xl transition-colors"
          >
            ×
          </button>
        </div>
        
        <div className="overflow-y-auto flex-1 pr-2">
          {loading ? (
             <div className="text-center py-12">
               <div className="animate-spin text-4xl mb-4">⌛</div>
               <p className="text-gray-500">正在加载数据...</p>
             </div>
          ) : leaderboard.length === 0 ? (
            <div className="text-center py-12">
              <div className="text-4xl mb-4">🏜️</div>
              <p className="text-gray-500">暂无记录，快去挑战吧！</p>
            </div>
          ) : (
            <table className="w-full text-sm">
              <thead className="bg-gray-50 text-xs uppercase text-gray-500 sticky top-0">
                <tr>
                  <th className="px-4 py-3 text-left rounded-tl-lg">排名</th>
                  <th className="px-4 py-3 text-left">玩家</th>
                  <th className="px-4 py-3 text-right">步数</th>
                  <th className="px-4 py-3 text-right rounded-tr-lg">日期</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {leaderboard.map((entry, idx) => (
                  <tr key={idx} className={`hover:bg-gray-50 transition-colors ${idx < 3 ? 'bg-yellow-50/30' : ''}`}>
                    <td className="px-4 py-3 font-medium text-gray-900">
                      {idx === 0 ? '🥇' : idx === 1 ? '🥈' : idx === 2 ? '🥉' : idx + 1}
                    </td>
                    <td className="px-4 py-3 text-gray-800 font-medium">{entry.nickname}</td>
                    <td className="px-4 py-3 text-right font-bold text-blue-600">{entry.score}</td>
                    <td className="px-4 py-3 text-right text-xs text-gray-400 whitespace-nowrap">
                      {entry.created_at ? new Date(entry.created_at).toLocaleDateString(undefined, { month: 'numeric', day: 'numeric' }) : '-'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default Leaderboard;