import React, { useState } from 'react';
import { useGameStore } from '../store/useGameStore';

const NicknameInput: React.FC = () => {
  const { setNickname } = useGameStore();
  const [input, setInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      setNickname(input.trim());
    }
  };

  return (
    <div className="fixed inset-0 bg-gray-100 flex items-center justify-center p-4 z-50">
      <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-md">
        <h1 className="text-3xl font-bold mb-2 text-center text-blue-600">寻机头 v4.0</h1>
        <p className="text-center text-gray-500 mb-8">全新挑战模式，创造你的关卡</p>
        
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">请输入你的游戏昵称</label>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="例如：机头猎手"
              required
              autoFocus
            />
          </div>
          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg transition-colors shadow-md hover:shadow-lg transform active:scale-95 duration-150"
          >
            开始游戏
          </button>
        </form>
      </div>
    </div>
  );
};

export default NicknameInput;